#include <iostream>
#include <cstdio>
using namespace std;

float calculateAverage(int arr[], int size) {
    int sum = 0;

    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }

    float avg = (float)sum / size;

    return avg;
}

int main() {
    int numbers[] = {10, 20, 30, 40};
    int size = 4;

    cout << "Average is: " << calculateAverage(numbers, size) << endl;

    if (size == 0) {
        cout << "Array is empty" << endl;
    } else {
        float result = calculateAverage(numbers, size);
        printf("%.2f\n", result);
    }

    return 0;
}

